(function(){
'use strict';
if(window.CRMPlaybookStudio) return;
const $=(s,r=document)=>r.querySelector(s),$$=(s,r=document)=>Array.from(r.querySelectorAll(s));
const esc=v=>String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const read=(k,fb)=>{try{const raw=localStorage.getItem(k);return raw?JSON.parse(raw):fb}catch(e){return fb}};
const write=(k,v)=>{try{localStorage.setItem(k,JSON.stringify(v))}catch(e){}};
const UI_KEY='crm_v987_playbook_studio_ui';
const engine=()=>window.CRMScriptEngine;
function state(){return Object.assign({tab:'blocks',playbookId:'',blockId:'',objectionId:'',previewLeadId:''},read(UI_KEY,{}))}
function saveState(s){write(UI_KEY,s)}
function notify(msg,type='success'){try{if(window.crmToast)return window.crmToast(msg,type);if(window.showToast)return window.showToast(msg,type)}catch(e){}console.log(msg)}
function getPlaybooks(){return engine()?.getPlaybooks?.()||[]}
function savePlaybooks(list){return engine()?.savePlaybooks?.(list)||list}
function getLeads(){try{return window.CRMData?.leads?.all?.()||window.CRMV94Official?.getLeads?.()||[]}catch(e){return[]}}
function currentPB(){const list=getPlaybooks(),st=state();return list.find(p=>p.id===st.playbookId)||list[0]||engine().defaultPlaybook()}
function ensureState(){const st=state(),list=getPlaybooks();if(!list.find(p=>p.id===st.playbookId))st.playbookId=list[0]?.id||'';const p=list.find(x=>x.id===st.playbookId)||list[0];if(p&&!p.scriptBlocks.find(b=>b.id===st.blockId))st.blockId=p.scriptBlocks[0]?.id||'';if(p&&!p.objecoes.find(o=>o.id===st.objectionId))st.objectionId=p.objecoes[0]?.id||'';saveState(st);return st}
function optionLines(block){return (block.options||[]).map(o=>`${o.label}${o.nextId?' | '+o.nextId:''}`).join('\n')}
function parseOptions(text){return String(text||'').split('\n').map(x=>x.trim()).filter(Boolean).map((line,i)=>{const [label,next='']=line.split('|').map(x=>x.trim());return engine().normalizeOption({label,value:label,nextId:next},i)})}
function blockList(p,st){return `<div class="v987-studio-list">${p.scriptBlocks.map((b,i)=>`<button type="button" class="${b.id===st.blockId?'active':''}" data-studio-block="${esc(b.id)}"><span>${i+1}</span><div><b>${esc(b.title)}</b><small>${esc(engine().BLOCK_LABELS[b.type]||b.type)}</small></div></button>`).join('')}</div>`}
function blockEditor(p,st){const b=p.scriptBlocks.find(x=>x.id===st.blockId)||p.scriptBlocks[0];if(!b)return'<div class="v987-studio-empty">Crie o primeiro bloco do roteiro.</div>';return `<div class="v987-studio-editor" data-editor-block="${esc(b.id)}"><div class="v987-studio-editor-head"><div><span>Bloco do roteiro</span><h2>${esc(b.title)}</h2></div><div><button data-block-move="up">↑</button><button data-block-move="down">↓</button><button class="danger" data-block-delete>Excluir</button></div></div><div class="v987-studio-fields"><label>Título<input data-block-field="title" value="${esc(b.title)}"></label><label>Tipo<select data-block-field="type">${engine().BLOCK_TYPES.map(t=>`<option value="${t}" ${b.type===t?'selected':''}>${esc(engine().BLOCK_LABELS[t])}</option>`).join('')}</select></label><label class="wide">Objetivo desta etapa<textarea data-block-field="objective">${esc(b.objective)}</textarea></label><label class="wide">Conteúdo / fala / pergunta<textarea data-block-field="content">${esc(b.content)}</textarea></label><label class="wide">Opções — uma por linha; use “Opção | id_do_próximo_bloco” para ramificar<textarea data-block-options>${esc(optionLines(b))}</textarea></label><label>Nota solicitada<input data-block-field="notePrompt" value="${esc(b.notePrompt)}"></label><label class="check"><input type="checkbox" data-block-field="required" ${b.required?'checked':''}> Obrigatório</label></div><div class="v987-studio-actions"><button class="primary" data-save-block>Salvar bloco</button><button data-duplicate-block>Duplicar</button><button data-add-block>+ Novo bloco</button></div></div>`}
function objectionsList(p,st){return `<div class="v987-studio-list">${p.objecoes.map(o=>`<button type="button" class="${o.id===st.objectionId?'active':''}" data-studio-objection="${esc(o.id)}"><span>!</span><div><b>${esc(o.nome)}</b><small>${esc(o.categoria)}</small></div></button>`).join('')||'<div class="v987-studio-empty">Nenhuma objeção cadastrada.</div>'}</div>`}
function objectionEditor(p,st){const o=p.objecoes.find(x=>x.id===st.objectionId)||p.objecoes[0];if(!o)return`<div class="v987-studio-editor"><div class="v987-studio-empty">Crie uma objeção para começar.</div><button class="primary" data-add-objection>+ Nova objeção</button></div>`;return `<div class="v987-studio-editor" data-editor-objection="${esc(o.id)}"><div class="v987-studio-editor-head"><div><span>Biblioteca de objeções</span><h2>${esc(o.nome)}</h2></div><button class="danger" data-delete-objection>Excluir</button></div><div class="v987-studio-fields"><label>Nome<input data-objection-field="nome" value="${esc(o.nome)}"></label><label>Categoria<input data-objection-field="categoria" value="${esc(o.categoria)}"></label><label class="wide">Frases que identificam a objeção<textarea data-objection-array="frases">${esc((o.frases||[]).join('\n'))}</textarea></label><label class="wide">Resposta principal<textarea data-objection-field="resposta">${esc(o.resposta)}</textarea></label><label class="wide">Resposta alternativa<textarea data-objection-field="alternativa">${esc(o.alternativa)}</textarea></label><label class="wide">Pergunta de aprofundamento<textarea data-objection-field="pergunta">${esc(o.pergunta)}</textarea></label><label class="wide">Argumento ou prova<textarea data-objection-field="argumento">${esc(o.argumento)}</textarea></label><label class="wide">Próxima ação<input data-objection-field="proximaAcao" value="${esc(o.proximaAcao)}"></label><label>Segmentos<textarea data-objection-array="segmentos">${esc((o.segmentos||[]).join('\n'))}</textarea></label><label>Etapas do script<textarea data-objection-array="etapas">${esc((o.etapas||[]).join('\n'))}</textarea></label></div><div class="v987-studio-actions"><button class="primary" data-save-objection>Salvar objeção</button><button data-add-objection>+ Nova objeção</button></div></div>`}
function preview(p,st){const leads=getLeads(),l=leads.find(x=>x.id===st.previewLeadId)||leads[0]||{};return `<div class="v987-studio-preview"><div class="v987-studio-preview-head"><label>Visualizar com o lead<select data-preview-lead>${leads.map(x=>`<option value="${esc(x.id)}" ${x.id===l.id?'selected':''}>${esc(x.empresa||x.nome)}</option>`).join('')}</select></label><button data-open-focus="${esc(l.id||'')}">Abrir Ligação em foco</button></div><div class="v987-preview-flow">${p.scriptBlocks.filter(b=>!b.hidden).map((b,i)=>`<article><span>${i+1}</span><div><small>${esc(engine().BLOCK_LABELS[b.type])}</small><h3>${esc(b.title)}</h3>${b.objective?`<b>${esc(b.objective)}</b>`:''}<p>${esc(engine().fill(b.content,l))}</p>${b.options?.length?`<div>${b.options.map(o=>`<em>${esc(o.label)}</em>`).join('')}</div>`:''}</div></article>`).join('')}</div></div>`}
function strategy(p){return `<div class="v987-strategy"><section><h2>Como este Playbook será usado</h2><p>O CRM cruza segmento e etapa de Follow-up. Durante a ligação, o roteiro fica no centro, enquanto as objeções e anotações aparecem na lateral direita.</p><div class="v987-strategy-grid"><div><span>Objetivo</span><b>${esc(p.objetivo)}</b></div><div><span>Blocos</span><b>${p.scriptBlocks.length}</b></div><div><span>Objeções</span><b>${p.objecoes.length}</b></div><div><span>Cadência</span><b>${p.cadencia.length} ações</b></div></div></section><section><h2>Dados do Playbook</h2><div class="v987-studio-fields"><label>Nome<input data-pb-field="nome" value="${esc(p.nome)}"></label><label>Segmento<input data-pb-field="segmento" value="${esc(p.segmento)}"></label><label>Etapa do Follow-up<input data-pb-field="etapa" value="${esc(p.etapa)}"></label><label>Canal<input data-pb-field="canal" value="${esc(p.canal)}"></label><label class="wide">Objetivo<textarea data-pb-field="objetivo">${esc(p.objetivo)}</textarea></label><label class="wide">Descrição<textarea data-pb-field="descricao">${esc(p.descricao)}</textarea></label></div><button class="primary" data-save-pb>Salvar dados</button></section></div>`}
function render(elArg){const el=elArg||$('#playbooks');if(!el)return;const st=ensureState(),list=getPlaybooks(),p=list.find(x=>x.id===st.playbookId)||list[0],callActive=!!window.CRMV987Ligacoes?.state?.().routine;el.className='view grid-view v987-playbooks-view'+(el.classList.contains('active')?' active':'');let body='';if(st.tab==='blocks')body=`<div class="v987-studio-work"><aside>${blockList(p,st)}</aside>${blockEditor(p,st)}</div>`;if(st.tab==='objections')body=`<div class="v987-studio-work"><aside>${objectionsList(p,st)}</aside>${objectionEditor(p,st)}</div>`;if(st.tab==='preview')body=preview(p,st);if(st.tab==='strategy')body=strategy(p);el.innerHTML=`<div class="v987-playbook-shell"><header class="v987-studio-hero"><div><span>Playbooks comerciais</span><h1>Script Builder e Biblioteca de Objeções</h1><p>Monte o roteiro por blocos, crie ramificações e conecte respostas, perguntas e objeções ao modo Ligação em foco.</p></div><div>${callActive?'<button class="primary" data-return-call>← Voltar à ligação</button>':''}<button class="primary" data-new-playbook>+ Novo playbook</button><button data-export-playbooks>Exportar</button></div></header><div class="v987-studio-top"><select data-select-playbook>${list.map(x=>`<option value="${esc(x.id)}" ${x.id===p.id?'selected':''}>${esc(x.nome)}</option>`).join('')}</select><nav><button class="${st.tab==='strategy'?'active':''}" data-studio-tab="strategy">Estratégia</button><button class="${st.tab==='blocks'?'active':''}" data-studio-tab="blocks">Roteiro</button><button class="${st.tab==='objections'?'active':''}" data-studio-tab="objections">Objeções</button><button class="${st.tab==='preview'?'active':''}" data-studio-tab="preview">Prévia</button></nav></div>${body}</div>`;bind(el)}
function mutatePB(fn){const list=getPlaybooks(),st=state(),i=list.findIndex(x=>x.id===st.playbookId);if(i<0)return;fn(list[i],st);list[i].updatedAt=new Date().toISOString();list[i].version=Number(list[i].version||1)+1;savePlaybooks(list);saveState(st);render()}
function bind(el){if(el._v987StudioBound)return;el._v987StudioBound=true;el.addEventListener('change',e=>{if(e.target.matches('[data-select-playbook]')){const st=state();st.playbookId=e.target.value;st.blockId='';st.objectionId='';saveState(st);render();return}if(e.target.matches('[data-preview-lead]')){const st=state();st.previewLeadId=e.target.value;saveState(st);render()}});el.addEventListener('click',e=>{
 if(e.target.closest('[data-return-call]')){window.setView?.('ligacoes');return}
 const tab=e.target.closest('[data-studio-tab]');if(tab){const st=state();st.tab=tab.dataset.studioTab;saveState(st);render();return}
 const b=e.target.closest('[data-studio-block]');if(b){const st=state();st.blockId=b.dataset.studioBlock;saveState(st);render();return}
 const o=e.target.closest('[data-studio-objection]');if(o){const st=state();st.objectionId=o.dataset.studioObjection;saveState(st);render();return}
 if(e.target.closest('[data-save-pb]')){mutatePB(p=>{$$('[data-pb-field]',el).forEach(i=>p[i.dataset.pbField]=i.value)});notify('Playbook atualizado.');return}
 if(e.target.closest('[data-save-block]')){mutatePB((p,st)=>{const block=p.scriptBlocks.find(x=>x.id===st.blockId);if(!block)return;$$('[data-block-field]',el).forEach(i=>block[i.dataset.blockField]=i.type==='checkbox'?i.checked:i.value);block.options=parseOptions($('[data-block-options]',el)?.value)});notify('Bloco salvo.');return}
 if(e.target.closest('[data-add-block]')){mutatePB((p,st)=>{const b=engine().normalizeBlock({id:engine().uid('block'),title:'Nova etapa',type:'speech',content:'Escreva aqui a fala ou pergunta.',objective:'Defina o objetivo desta etapa.'},p.scriptBlocks.length);p.scriptBlocks.push(b);st.blockId=b.id});return}
 if(e.target.closest('[data-duplicate-block]')){mutatePB((p,st)=>{const src=p.scriptBlocks.find(x=>x.id===st.blockId);if(!src)return;const b=engine().normalizeBlock({...engine().clone(src),id:engine().uid('block'),title:src.title+' — cópia'},p.scriptBlocks.length);p.scriptBlocks.push(b);st.blockId=b.id});return}
 const mv=e.target.closest('[data-block-move]');if(mv){mutatePB((p,st)=>{const i=p.scriptBlocks.findIndex(x=>x.id===st.blockId),j=i+(mv.dataset.blockMove==='up'?-1:1);if(i>=0&&j>=0&&j<p.scriptBlocks.length)[p.scriptBlocks[i],p.scriptBlocks[j]]=[p.scriptBlocks[j],p.scriptBlocks[i]]});return}
 if(e.target.closest('[data-block-delete]')){mutatePB((p,st)=>{if(p.scriptBlocks.length<=1)return notify('O roteiro precisa ter pelo menos um bloco.','warn');const i=p.scriptBlocks.findIndex(x=>x.id===st.blockId);p.scriptBlocks.splice(i,1);st.blockId=p.scriptBlocks[Math.max(0,i-1)]?.id||''});return}
 if(e.target.closest('[data-save-objection]')){mutatePB((p,st)=>{const obj=p.objecoes.find(x=>x.id===st.objectionId);if(!obj)return;$$('[data-objection-field]',el).forEach(i=>obj[i.dataset.objectionField]=i.value);$$('[data-objection-array]',el).forEach(i=>obj[i.dataset.objectionArray]=i.value.split('\n').map(x=>x.trim()).filter(Boolean))});notify('Objeção salva.');return}
 if(e.target.closest('[data-add-objection]')){mutatePB((p,st)=>{const o=engine().normalizeObjection({id:engine().uid('obj'),nome:'Nova objeção',categoria:'Geral',resposta:'Escreva a resposta sugerida.'},p.objecoes.length);p.objecoes.push(o);st.objectionId=o.id});return}
 if(e.target.closest('[data-delete-objection]')){mutatePB((p,st)=>{const i=p.objecoes.findIndex(x=>x.id===st.objectionId);p.objecoes.splice(i,1);st.objectionId=p.objecoes[Math.max(0,i-1)]?.id||''});return}
 if(e.target.closest('[data-new-playbook]')){const list=getPlaybooks(),p=engine().normalizePlaybook({...engine().defaultPlaybook(),id:engine().uid('pb'),nome:'Novo playbook'});list.push(p);savePlaybooks(list);const st=state();st.playbookId=p.id;st.blockId=p.scriptBlocks[0]?.id||'';st.tab='strategy';saveState(st);render();return}
 if(e.target.closest('[data-export-playbooks]')){const blob=new Blob([JSON.stringify(getPlaybooks(),null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='playbooks-realtalent.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000);return}
 const focus=e.target.closest('[data-open-focus]');if(focus&&focus.dataset.openFocus){window.CRMV987Ligacoes?.openLead(focus.dataset.openFocus,{origin:{view:'playbooks'}}).catch(()=>{});return}
 });}
function open(playbookId,options={}){const st=state();if(playbookId)st.playbookId=playbookId;st.tab='blocks';st.returnToCall=!!options.returnToCall;saveState(st);window.setView?.('playbooks');setTimeout(()=>render(),30)}
const api={version:'98.7',render,open,state,getPlaybooks,savePlaybooks};window.CRMPlaybookStudio=api;
document.addEventListener('crm:playbooks-updated',()=>{if($('#playbooks.active'))render()});
if($('#playbooks.active'))setTimeout(()=>render(),40);
})();
